const { list, getValue, setValue } = this;
let listNew = [];

const getStatus = (content) => {
    let status = content.match(/<li><strong>Status<\/strong>\s*:\s*(.+?)<\/li>/);
    if (status) {
        return status[0];
    }
    return '<li><strong>Status</strong> : New</li>';
};

const getStatusValue = (content, label) => {
    let regex = new RegExp(`<li><strong>${label}</strong>\\s*:\\s*(.+?)</li>`)
    return content.match(regex)
    // return content.match(/<li><strong>Status<\/strong>\s*:\s*(.+?)<\/li>/);
};

const translateContent = (content, lang) => {
