const translation = (content, lang) => {
    const statusLabel = translateContent("Status", lang);
    const raLabel = translateContent("Request asset", lang);
    const ttoLabel = translateContent("Transfer to onsite", lang);
    const orLabel = translateContent("Onsite Resolve", lang);
    const eatLabel = translateContent("Expected Arrival Time", lang);
    const newLabel = translateContent("New", lang);
    const inProgressLabel = translateContent("In Progress", lang);
    const onHoldLabel = translateContent("On Hold", lang);
    const resolvedLabel = translateContent("Resolved", lang);
    const cancelledLabel = translateContent("Cancelled", lang);
    content = content.replace(/Status/, statusLabel);
    content = content.replace(/状态/, statusLabel);
    content = content.replace(/狀態/, statusLabel);
    content = content.replace(/Request asset/, raLabel);
    content = content.replace(/Transfer to onsite/, ttoLabel);
    content = content.replace(/Onsite Resolve/, orLabel);
    content = content.replace(/Expected Arrival Time/, eatLabel);

    content = content.replace(/New/, newLabel);
    content = content.replace(/In Progress/, inProgressLabel);
    content = content.replace(/On Hold/, onHoldLabel);
    content = content.replace(/Resolved/, resolvedLabel);
    content = content.replace(/Cancelled/, cancelledLabel);
    return content;
};

let expectedArrivalTime = "";
const lang = localStorage.getItem('i18nextLng'); // Detect browser language

for (let item of list) {
    const typ = getValue(item.values, "type");
    const operationDetails = getValue(item.values, "operationDetails");
    if (typ === "b" && operationDetails !== "Onsite-Resolve" && operationDetails !== "Request asset") {
        continue;
    }
    let content = getValue(item.values, "content");
    if (!content || !operationDetails) {
        continue;
    }

    if (operationDetails === "Incident-Insert") {
        let addContent = translateContent("Case created and we are escalating your case to the relevant engineer", lang);
        setValue(item.values, "content", translation(getStatus(content) + addContent, lang));
    } else if (operationDetails.includes("Assignment Group")) {
        let str = translateContent("Escalation support is required and we’ve escalated your case to a specialized team. They are now reviewing the details to ensure a swift resolution.", lang);
        setValue(item.values, "content", translation(getStatus(content) + str, lang));
    } else if (operationDetails.includes("Status")) {
        // console.log("Status: "+content)
        let sv = getStatusValue(content, "Status");
        let field = sv[1];
        if (field === "In Progress") {
            let str = translateContent("Your case is currently being handled by engineer", lang);
            setValue(item.values, "content", translation(sv[0] + str, lang));
        } else if (field === "Resolved") {
            let str = translateContent("Your case has been successfully closed. \nThank you for contacting HKT EMS Service Center", lang);
            setValue(item.values, "content", translation(sv[0] + str, lang));
        } else {
            continue;
        }
    } else if (operationDetails.includes("状态")) {
        // console.log("狀態"+content)
        let sv = getStatusValue(content, "状态");
        let field = sv[1];
        if (field === "In Progress") {
            let str = translateContent("Your case is currently being handled by engineer", lang);
            setValue(item.values, "content", translation(sv[0] + str, lang));
        } else if (field === "Resolved") {
            let str = translateContent("Your case has been successfully closed. \nThank you for contacting HKT EMS Service Center", lang);
            setValue(item.values, "content", translation(sv[0] + str, lang));
        } else {
            continue;
        }
    } else if (operationDetails.includes("狀態")) {
        // console.log("狀態"+content)
        let sv = getStatusValue(content, "狀態");
        let field = sv[1];
        if (field === "In Progress") {
            let str = translateContent("Your case is currently being handled by engineer", lang);
            setValue(item.values, "content", translation(sv[0] + str, lang));
        } else if (field === "Resolved") {
            let str = translateContent("Your case has been successfully closed. \nThank you for contacting HKT EMS Service Center", lang);
            setValue(item.values, "content", translation(sv[0] + str, lang));
        } else {
            continue;
        }
    } else if (operationDetails.includes("Transfer to onsite")) {
        setValue(item.values, "title", translation("Transfer to onsite", lang));
        let str = translateContent("Onsite support is required.", lang);
        let contentMatch = getValue(item.values, "content").match(/<li><strong>Expected Arrival Time<\/strong>\s*:\s*(.+?)<\/li>/);
        if (contentMatch && contentMatch.length >= 2) {
            setValue(item.values, "content", translation(contentMatch[0] + str, lang));
            expectedArrivalTime = contentMatch[0] + str;
        } else {
            if (expectedArrivalTime === "") {
                setValue(item.values, "content", " ");
            } else {
                setValue(item.values, "content", translation(expectedArrivalTime, lang));
            }
        }
    } else if (operationDetails.includes("Onsite-Resolve")) {
        setValue(item.values, "title", translation("Onsite Resolve", lang));
        setValue(item.values, "content", translation(translateContent("Your case has been resolved by onsite engineer。", lang), lang));
    } else if (operationDetails.includes("Request asset")) {
        setValue(item.values, "title", translation("Request asset", lang));
        let str = translateContent("Requested asset have been prepared.", lang);
        let contentMatch = getValue(item.values, "content").match(/<li><strong>Maxim's No<\/strong>\s*:\s*(.+?)<\/li>/);
        if (contentMatch && contentMatch.length >= 2) {
            setValue(item.values, "content", translation(str + contentMatch[0], lang));
        } else {
            setValue(item.values, "content", " ");
        }
    } else {
        continue;
    }
    listNew.push(item);
}

// Sort by operationTime in descending order
listNew.sort((a, b) => new Date(getValue(b.values, "operationTime")) - new Date(getValue(a.values, "operationTime")));

return listNew;

